import React, { useState, useEffect } from 'react';
import NavBar from '../../components/NavBar/NavBar';
import Waveform from '../../components/Waveform/Waveform';
import './Record.css';

function WhileRecord({ analyserNode, onPause, onSave, maxDuration = 180 }) {
  const [elapsed, setElapsed] = useState(0);

  useEffect(() => {
    const interval = setInterval(() => {
      setElapsed((prev) => {
        if (prev >= maxDuration) {
          clearInterval(interval);
          if (onSave) onSave(maxDuration);
          return maxDuration;
        }
        return prev + 1;
      });
    }, 1000);
    return () => clearInterval(interval);
  }, [maxDuration, onSave]);

  const formatTime = (s) => `${Math.floor(s / 60)}:${(s % 60).toString().padStart(2, '0')}`;
  const progress = (elapsed / maxDuration) * 100;

  return (
    <div className="screen">
      <div className="screen-content">
        <div className="status-badge recording">
          <span className="pulse-dot" />
          Recording
        </div>

        <div className="timer">
          {formatTime(elapsed)}
          <span className="duration"> / {formatTime(maxDuration)}</span>
        </div>

        <Waveform analyserNode={analyserNode} mode="recording" />

        <div className="progress-bar">
          <div className="progress-fill" style={{ width: `${progress}%` }} />
        </div>

        <div className="btn-row">
          <button className="btn btn-pause" onClick={() => onPause(elapsed)}>
            ⏸ Pause
          </button>
          <button className="btn btn-save" onClick={() => onSave(elapsed)}>
            ✓ Save
          </button>
        </div>
      </div>
      <NavBar active="record" />
    </div>
  );
}

export default WhileRecord;
